<template><div class="modern-page"><section class="modern-hero"><h1>Notificações</h1><p>Todas as notificações reais enviadas pelo sistema ou por utilizadores, incluindo falhadas.</p><div class="hero-actions"><button class="btn" @click="load">Actualizar</button><button class="btn btn-danger-soft" @click="retryAll">Reenviar falhadas</button></div></section><div class="modern-card"><table class="modern-table"><thead><tr><th>Data</th><th>Canal</th><th>Evento</th><th>Destinatário</th><th>Estado</th><th>Acções</th></tr></thead><tbody><tr v-for="n in logs" :key="n.id"><td>{{date(n.created_at)}}</td><td><span class="ch-pill" :class="'ch-'+n.channel">{{n.channel}}</span></td><td>{{n.event}}</td><td>{{n.recipient_email||n.recipient_phone}}</td><td><StatusBadge :status="n.status" /></td><td><button class="btn btn-sm" @click="view(n)">Ver log</button><button v-if="n.status==='failed'" class="btn btn-sm btn-danger-soft" @click="retry(n)">Reenviar</button></td></tr></tbody></table></div><div v-if="selected" class="modal-backdrop" @click.self="selected=null"><div class="mk-modal wide"><div class="mk-modal-head"><h2>Log de notificação</h2><button class="modal-x" @click="selected=null">×</button></div><pre class="log-box">{{JSON.stringify(selected,null,2)}}</pre></div></div></div></template>
<script setup>import {ref,onMounted} from 'vue'; import {useToast} from 'vue-toastification'; import api from '@/services/api'; import StatusBadge from '@/components/common/StatusBadge.vue'; const toast=useToast(); const logs=ref([]), selected=ref(null); const date=d=>d?new Date(d).toLocaleString('pt-MZ'):''; async function load(){try{const {data}=await api.get('/notifications/logs',{params:{limit:200}}); logs.value=data.data||[]}catch(e){toast.error(e.response?.data?.message||'Erro ao carregar notificações')}} function view(n){selected.value=n} async function retry(n){try{await api.post('/notifications/retry/'+n.id); toast.success('Notificação reenviada/colocada em fila'); await load()}catch(e){toast.error(e.response?.data?.message||'Erro ao reenviar')}} async function retryAll(){try{await api.post('/notifications/retry'); toast.success('Falhadas colocadas em fila'); await load()}catch(e){toast.error(e.response?.data?.message||'Erro ao reenviar')}} onMounted(load)</script><style scoped>.log-box{background:var(--mk-surface-2);padding:12px;border-radius:8px;max-height:420px;overflow:auto;font-size:12px}</style>
